echo '<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Plagas SSH Mini</title><style>*{margin:0;padding:0;box-sizing:border-box}body{background:#1a1a1a;color:#e0e0e0;font-family:-apple-system,sans-serif;font-size:13px}.tb{background:#2a2a2a;border-bottom:1px solid #111;padding:8px 16px;display:flex;align-items:center;position:sticky;top:0;z-index:100}.tb h1{font-size:13px;color:#ddd;flex:1;text-align:center}.dm{color:#888;font-size:11px}.mn{padding:16px;max-width:960px;margin:0 auto}.cd{background:#222;border:1px solid #3a3a3a;border-radius:8px;padding:14px;margin-bottom:12px}.ig{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:10px}.ii{background:#2a2a2a;border:1px solid #3a3a3a;border-radius:6px;padding:8px 12px}.il{font-size:9px;color:#999;text-transform:uppercase}.iv{font-family:monospace;font-size:11px}.tg{color:#2ecc71}.tr{color:#e74c3c}.to{color:#e67e22}.term{background:#0d0d0d;border:1px solid #3a3a3a;border-radius:6px;padding:10px;font-family:monospace;font-size:11px;min-height:250px;max-height:400px;overflow-y:auto;white-space:pre-wrap;word-wrap:break-word;line-height:1.5;color:#2ecc71}.term .cl{color:#1abc9c}.term .el{color:#e74c3c}.ci{display:flex;gap:6px;margin-top:8px;align-items:center}.ci .pr{color:#1abc9c;font-family:monospace;font-size:12px;white-space:nowrap}.ci input{flex:1;background:#2a2a2a;border:1px solid #3a3a3a;color:#2ecc71;font-family:monospace;font-size:12px;padding:8px;border-radius:6px}.ci input:focus{outline:none;border-color:#2ecc71}.bt{padding:4px 10px;border:none;border-radius:4px;font-size:11px;font-weight:600;cursor:pointer}.b-g{background:#2ecc71;color:#1a1a1a}.b-r{background:#e74c3c;color:#fff}.b-o{background:#e67e22;color:#fff}.b-b{background:#3498db;color:#fff}.b-h{background:transparent;border:1px solid #3a3a3a;color:#e0e0e0}.qb{display:flex;gap:4px;flex-wrap:wrap;margin-bottom:8px}.qb .bt{font-family:monospace;font-size:10px;padding:3px 8px}.tabs{display:flex;gap:2px;background:#2a2a2a;border-radius:6px;padding:2px;margin-bottom:12px}.tab{padding:6px 16px;border-radius:4px;font-size:12px;font-weight:600;cursor:pointer;color:#999;border:none;background:transparent}.tab.on{background:#e74c3c;color:#fff}.fm-path{background:#2a2a2a;border:1px solid #3a3a3a;border-radius:4px;padding:6px 10px;font-family:monospace;font-size:11px;color:#1abc9c;margin-bottom:8px;display:flex;align-items:center;gap:8px}.fm-path input{flex:1;background:transparent;border:none;color:#1abc9c;font-family:monospace;font-size:11px;outline:none}.fm-list{max-height:400px;overflow-y:auto}.fm-row{display:flex;align-items:center;padding:6px 10px;border-bottom:1px solid #2a2a2a;font-size:11px;cursor:pointer;gap:8px}.fm-row:hover{background:#2a2a2a}.fm-icon{width:16px;text-align:center}.fm-name{flex:1;font-family:monospace}.fm-dir{color:#3498db}.fm-file{color:#e0e0e0}.fm-size{color:#666;width:70px;text-align:right;font-family:monospace;font-size:10px}.fm-perm{color:#666;width:40px;font-family:monospace;font-size:10px}.fm-time{color:#555;width:110px;font-size:10px}.fm-acts{display:flex;gap:4px}.fm-bar{display:flex;gap:6px;margin-bottom:8px;flex-wrap:wrap}.editor{width:100%;background:#0d0d0d;border:1px solid #3a3a3a;color:#2ecc71;font-family:monospace;font-size:11px;padding:10px;border-radius:6px;min-height:300px;resize:vertical}</style></head><body>
